### ChatClientAgentOptions

Configuration options for agent creation and behavior.

```csharp
public class ChatClientAgentOptions
{
    // Basic metadata
    public string? Id { get; set; }
    public string? Name { get; set; }
    public string? Description { get; set; }

    // Chat configuration
    public ChatOptions? ChatOptions { get; set; }

    // History and context
    public ChatHistoryProvider? ChatHistoryProvider { get; set; }
    public List<AIContextProvider>? AIContextProviders { get; set; }

    // Behavior control
    public bool UseProvidedChatClientAsIs { get; set; }
        // If true: use IChatClient without default decorators
        // If false (default): apply automatic function invocation and other decorators

    // Chat history conflict handling
    public bool ClearOnChatHistoryProviderConflict { get; set; } = true;
        // Clear ChatHistoryProvider if service manages history

    public bool WarnOnChatHistoryProviderConflict { get; set; } = true;
        // Log warning if conflict detected

    public bool ThrowOnChatHistoryProviderConflict { get; set; } = true;
        // Throw exception if conflict detected

    public bool RequirePerServiceCallChatHistoryPersistence { get; set; }
        // Persist history after each service call within FunctionInvokingChatClient loop
}
```

