## 3. Message Types and History

### ChatMessage

```csharp
public class ChatMessage
{
    // Constructors
    public ChatMessage()  // Defaults to role: User
    public ChatMessage(ChatRole role, string content)
    public ChatMessage(ChatRole role, IList<AIContent> contents)

    // Core properties
    public ChatRole Role { get; set; }  // User, Assistant, System, Tool
    public string Text { get; }  // Concatenated text from TextContent items
    public IList<AIContent> Contents { get; set; }

    // Metadata
    public string? AuthorName { get; set; }
    public string? MessageId { get; set; }
    public DateTimeOffset? CreatedAt { get; set; }
    public object? RawRepresentation { get; set; }  // Original underlying object
    public AdditionalPropertiesDictionary? AdditionalProperties { get; set; }

    // Operations
    public ChatMessage Clone()  // Shallow clone
    public override string ToString()
}

public enum ChatRole
{
    User,
    Assistant,
    System,
    Tool
}
```

