### ChatOptions

Configuration for chat requests.

```csharp
public class ChatOptions
{
    public ChatOptions()
    public ChatOptions(ChatOptions other)  // Copy constructor

    // Conversation management
    public string? ConversationId { get; set; }
        // Identifier for stateful multi-turn conversations

    // LLM behavior
    public string? Instructions { get; set; }
        // Per-request instructions (combined with system instructions)

    public double? Temperature { get; set; }
        // Randomness: lower = deterministic, higher = creative

    public int? MaxOutputTokens { get; set; }

    public double? TopP { get; set; }
        // Nucleus sampling: probability threshold

    public int? TopK { get; set; }
        // Top-K most probable tokens considered

    public double? FrequencyPenalty { get; set; }
        // Reduce repetition of tokens

    public double? PresencePenalty { get; set; }
        // Reduce all previously appeared tokens equally

    public int? Seed { get; set; }
        // For reproducibility

    // Tool/Function calling
    public IList<AITool>? Tools { get; set; }
    public ChatToolMode? ToolMode { get; set; }  // Auto, None, Required, Specific

    // Response formatting
    public ChatResponseFormat? ResponseFormat { get; set; }
        // Text, Json, or custom schema

    // Advanced reasoning
    public ReasoningOptions? Reasoning { get; set; }
}

public abstract class ChatToolMode
{
    public static ChatToolMode None { get; }
    public static ChatToolMode Auto() => new AutoChatToolMode();
    public static ChatToolMode Required() => new RequiredChatToolMode();
    public static ChatToolMode Specific(params AITool[] tools) => ...
}
```

