    object? GetService(Type serviceType, object? serviceKey = null)
}
```

---

### OpenAI Integration

Creating OpenAI-backed chat clients.

```csharp
// Using OpenAI SDK directly
using OpenAI.Chat;
var openAIClient = new ChatClient("gpt-4o", "your-api-key");

// Convert to IChatClient
var chatClient = openAIClient.AsIChatClient();

// Use with agent
var agent = new ChatClientAgent(
    chatClient,
    instructions: "You are a helpful research assistant.",
    name: "ResearchBot",
    description: "Performs research and analysis"
);
```

**OpenAI ChatClient Constructor:**
```csharp
public OpenAIChatClient(OpenAI.Chat.ChatClient chatClient)
```

**Extension Methods:**
```csharp
public static IChatClient AsIChatClient(this ChatClient chatClient)
public static IChatClient AsIChatClient(this OpenAI.OpenAIClient client)
```

