using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capabilities using the DuckDuckGo instant-answer API
/// and direct page fetching for deeper research.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Search the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_redirect=1&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetFromJsonAsync<DuckDuckGoResponse>(url, cancellationToken);

            var results = new List<SearchResult>();

            // Add the abstract (main answer) if available
            if (!string.IsNullOrWhiteSpace(response?.Abstract))
            {
                results.Add(new SearchResult(
                    response.Heading ?? query,
                    response.Abstract,
                    response.AbstractURL ?? ""));
            }

            // Add related topics
            if (response?.RelatedTopics is not null)
            {
                foreach (var topic in response.RelatedTopics)
                {
                    if (results.Count >= maxResults)
                        break;

                    if (!string.IsNullOrWhiteSpace(topic.Text))
                    {
                        results.Add(new SearchResult(
                            topic.Text.Length > 80 ? topic.Text[..80] + "..." : topic.Text,
                            topic.Text,
                            topic.FirstURL ?? ""));
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No results found for '{query}'. Try rephrasing the search query or breaking it into simpler terms.";
            }

            return FormatResults(query, results);
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}. Try a different query or use FetchWebPage to read a specific URL.";
        }
    }

    [Description("Fetch and extract the text content from a specific web page URL. Use this to read full articles or documentation pages.")]
    public async Task<string> FetchWebPageAsync(
        [Description("The full URL of the web page to fetch")] string url,
        [Description("Maximum number of characters to return from the page")] int maxLength = 3000,
        CancellationToken cancellationToken = default)
    {
        maxLength = Math.Clamp(maxLength, 500, 8000);

        try
        {
            var response = await _httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var text = StripHtml(html);

            if (text.Length > maxLength)
                text = text[..maxLength] + "\n... [truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? $"Could not extract meaningful text from {url}."
                : $"Content from {url}:\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch {url}: {ex.Message}";
        }
    }

    private static string FormatResults(string query, List<SearchResult> results)
    {
        var lines = new List<string> { $"Search results for '{query}':", "" };

        for (var i = 0; i < results.Count; i++)
        {
            var r = results[i];
            lines.Add($"[{i + 1}] {r.Title}");
            lines.Add($"    {r.Snippet}");
            if (!string.IsNullOrWhiteSpace(r.Url))
                lines.Add($"    URL: {r.Url}");
            lines.Add("");
        }

        return string.Join('\n', lines);
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        html = System.Text.RegularExpressions.Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", " ", System.Text.RegularExpressions.RegexOptions.Singleline | System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        // Replace block tags with newlines
        html = System.Text.RegularExpressions.Regex.Replace(html, @"<(br|p|div|h[1-6]|li|tr)[^>]*>", "\n", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        // Strip remaining tags
        html = System.Text.RegularExpressions.Regex.Replace(html, @"<[^>]+>", " ");
        // Decode common entities
        html = System.Net.WebUtility.HtmlDecode(html);
        // Collapse whitespace
        html = System.Text.RegularExpressions.Regex.Replace(html, @"[ \t]+", " ");
        html = System.Text.RegularExpressions.Regex.Replace(html, @"\n{3,}", "\n\n");
        return html.Trim();
    }

    private sealed record SearchResult(string Title, string Snippet, string Url);

    private sealed class DuckDuckGoResponse
    {
        [JsonPropertyName("Abstract")]
        public string? Abstract { get; set; }

        [JsonPropertyName("AbstractURL")]
        public string? AbstractURL { get; set; }

        [JsonPropertyName("Heading")]
        public string? Heading { get; set; }

        [JsonPropertyName("RelatedTopics")]
        public List<DuckDuckGoTopic>? RelatedTopics { get; set; }
    }

    private sealed class DuckDuckGoTopic
    {
        [JsonPropertyName("Text")]
        public string? Text { get; set; }

        [JsonPropertyName("FirstURL")]
        public string? FirstURL { get; set; }
    }
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to organize
/// findings, key facts, and source references during research.
/// </summary>
public sealed class NoteTaker
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a category tag. Use this to record key findings, facts, quotes, or source references as you research.")]
    public string SaveNote(
        [Description("The content of the note to save")] string content,
        [Description("A short category tag (e.g., 'key-fact', 'source', 'quote', 'definition', 'statistic')")] string category = "general")
    {
        var note = new Note(
            Id: _notes.Count + 1,
            Content: content,
            Category: category.ToLowerInvariant().Trim(),
            Timestamp: DateTimeOffset.UtcNow);

        _notes.Add(note);
        return $"Note #{note.Id} saved under '{note.Category}'. Total notes: {_notes.Count}.";
    }

    [Description("Retrieve all saved research notes, optionally filtered by category. Use this to review what you've gathered before writing a summary.")]
    public string GetNotes(
        [Description("Optional category filter. Pass empty string or 'all' to get all notes.")] string category = "all")
    {
