using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capabilities for the research agent to organize
/// findings, key facts, and source references during research.
/// </summary>
public sealed class NoteTaker
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a category tag. Use this to record key findings, facts, quotes, or source references as you research.")]
    public string SaveNote(
        [Description("The content of the note to save")] string content,
        [Description("A short category tag (e.g., 'key-fact', 'source', 'quote', 'definition', 'statistic')")] string category = "general")
    {
        var note = new Note(
            Id: _notes.Count + 1,
            Content: content,
            Category: category.ToLowerInvariant().Trim(),
            Timestamp: DateTimeOffset.UtcNow);

        _notes.Add(note);
        return $"Note #{note.Id} saved under '{note.Category}'. Total notes: {_notes.Count}.";
    }

    [Description("Retrieve all saved research notes, optionally filtered by category. Use this to review what you've gathered before writing a summary.")]
    public string GetNotes(
        [Description("Optional category filter. Pass empty string or 'all' to get all notes.")] string category = "all")
    {
        var filtered = string.IsNullOrWhiteSpace(category) || category.Equals("all", StringComparison.OrdinalIgnoreCase)
            ? _notes
            : _notes.Where(n => n.Category.Equals(category.Trim(), StringComparison.OrdinalIgnoreCase)).ToList();

        if (filtered.Count == 0)
        {
            return category == "all"
                ? "No notes saved yet."
                : $"No notes found for category '{category}'. Available categories: {string.Join(", ", _notes.Select(n => n.Category).Distinct())}.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"Research Notes ({filtered.Count} of {_notes.Count} total):");
        sb.AppendLine(new string('-', 50));

        foreach (var note in filtered)
        {
            sb.AppendLine($"[#{note.Id}] [{note.Category}] {note.Content}");
        }

        return sb.ToString();
    }

    [Description("Get a summary of note counts by category to understand research coverage.")]
    public string GetNoteStats()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var stats = _notes
            .GroupBy(n => n.Category)
            .Select(g => $"  {g.Key}: {g.Count()}")
            .ToList();

        return $"Note Statistics (total: {_notes.Count}):\n{string.Join('\n', stats)}";
    }

    private sealed record Note(int Id, string Content, string Category, DateTimeOffset Timestamp);
}

